#[allow(unused_imports)]
use std::fmt::Write as _;
use logicaffeine_data::*;
use logicaffeine_system::*;

fn args() -> LogosSeq<String> {
    logicaffeine_system::env::args()
}

fn parseInt(s: String) -> i64 {
    logicaffeine_system::text::parseInt(s)
}

#[inline]
fn makeCheck(depth: i64) -> i64 {
    if depth == 0 { return 1; }
    (2i64.wrapping_mul((if (depth as u64) >= 64 { 0i64 } else { 1i64 << depth }))).wrapping_sub(1)
}

fn main() {
    std::thread::Builder::new()
        .stack_size(67_108_864)
        .spawn(_logos_main)
        .unwrap().join().unwrap();
}
fn _logos_main() {
    let arguments = args();
    let n = parseInt(arguments.borrow()[1].clone());
    let minDepth = 4;
    let mut maxDepth = n;
    if (6 > maxDepth) {
        maxDepth = 6;
    }
    let stretchCheck = makeCheck(logos_add_exact(maxDepth, 1).expect_i64("Int"));
    show(&format!("{}{}{}{}", "stretch tree of depth ", logos_add_exact(maxDepth, 1), " check: ", stretchCheck));
    let longLived = makeCheck(maxDepth);
    let mut depth = 4;
    while (depth <= maxDepth) {
        let mut iterations = 1;
        let mut p = 0;
        if (logos_add_exact(logos_sub_exact(maxDepth, depth), 4).expect_i64("Int") > 0) {
            iterations = (1 << logos_add_exact(logos_sub_exact(maxDepth, depth), 4).expect_i64("Int"));
            p = logos_add_exact(logos_sub_exact(maxDepth, depth), 4).expect_i64("Int");
        }
        let mut totalCheck = 0;
        for i in 0..iterations {
            totalCheck = (totalCheck + makeCheck(depth));
        }
        show(&format!("{}{}{}{}{}{}", "", iterations, " trees of depth ", depth, " check: ", totalCheck));
        depth = logos_add_exact(depth, 2).expect_i64("Int");
    }
    show(&format!("{}{}{}{}", "long lived tree of depth ", maxDepth, " check: ", longLived));
}
